const Sequelize = require('sequelize');
const { Op } = Sequelize;

const usedValidations = await ValidationConsumption.findAll({
  attributes: [
    'validationId',
    [Sequelize.fn('COUNT', Sequelize.col('*')), 'count'],
  ],
  where,
  group: ['validationId'],
